// ============================================================
// DISPATCHER-WATCHDOG (Paket 7, Architekturpruefung 2026-07-22)
// ============================================================
// Reiner Lese-/Alarm-Workflow: schreibt NICHTS in allris_vorgaenge, ruft
// keinen anderen Workflow aktiv auf. Findet Vorgaenge, die laenger als
// STALE_HOURS in einem Zwischenzustand haengen, obwohl die naechste Stufe
// sie laengst haette abholen muessen (die 5h-Kaskade laeuft mehrfach in
// dieser Zeit). Nutzt ausschliesslich bereits vorhandene Felder - keine
// Abhaengigkeit von Paket 2 (State-History/Fehlercodes), die noch nicht
// angelegt sind.
//
// Ergaenzt (nicht ersetzt) die stufeneigenen Selbstheilungs-/Alert-Pfade,
// die es schon gibt (z.B. P4s Blockade-Alert, P2s archiving_failed-Alert,
// P5bs Erinnerungen) - diese pruefen jeweils nur ihre eigene Stufe. Dieser
// Workflow schaut stufenuebergreifend auf "haette laengst weiter sein
// muessen, ist es aber nicht".
//
// Absichtlich sehr konservativ gehalten: nur 4 klar begruendbare Checks,
// grosszuegige Schwellwerte (24h = ca. 5 verpasste Kaskaden-Durchlaeufe),
// um Fehlalarme durch normale Laufzeitschwankungen (siehe bekanntes
// Proxy-Langsamkeits-Thema) zu vermeiden.

const STALE_HOURS = 24;
const STALE_MS = STALE_HOURS * 60 * 60 * 1000;

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function ageMs(iso) {
  if (!iso) return null;
  const t = Date.parse(iso);
  return Number.isFinite(t) ? (Date.now() - t) : null;
}
function isStale(iso) {
  const a = ageMs(iso);
  return a !== null && a > STALE_MS;
}

const rows = $input.all().map(i => i.json || {});
const findings = [];

for (const j of rows) {
  const vorgangKey = safeStr(j.vorgangKey);
  if (!vorgangKey) continue;
  const label = safeStr(j.vorgangsnummer) + ' – ' + safeStr(j.title);

  // Check 1: seit Ingestion laenger als STALE_HOURS bei needs_summary haengen
  // geblieben (P3 haette es laengst zusammengefasst haben muessen).
  if (safeStr(j.contentStage) === 'needs_summary' && isStale(j.firstseen)) {
    findings.push({
      vorgangKey, label,
      check: 'ingestion_to_summary',
      hint: 'contentStage=needs_summary seit über ' + STALE_HOURS + 'h (firstseen=' + safeStr(j.firstseen) + ') - Bewertung (P3) hat es nicht abgeholt.'
    });
  }

  // Check 2: needs_content, aber Agenten-Kette (P3d) ist nie gelaufen.
  if (safeStr(j.contentStage) === 'needs_content' &&
      !safeStr(j.judgmentChainProcessedAt) &&
      isStale(j.lastAnalysisAt)) {
    findings.push({
      vorgangKey, label,
      check: 'analysis_to_judgment',
      hint: 'lastAnalysisAt seit über ' + STALE_HOURS + 'h gesetzt, aber judgmentChainProcessedAt fehlt weiterhin - Agenten-Kette (P3d) hat es nicht abgeholt.'
    });
  }

  // Check 3: Eignungs-Agent hat Sharepic freigegeben, aber Kernbotschaft
  // (P3e) hat nie eine Auswahl angestossen.
  if (safeStr(j.sharepicNeedStage) === 'topic_ok' &&
      !safeStr(j.headlineChoiceStage) &&
      isStale(j.lastAnalysisAt)) {
    findings.push({
      vorgangKey, label,
      check: 'judgment_to_kernbotschaft',
      hint: 'sharepicNeedStage=topic_ok seit über ' + STALE_HOURS + 'h, aber headlineChoiceStage ist weiterhin leer - Kernbotschaft-Stufe (P3e) hat es nicht abgeholt.'
    });
  }

  // Check 4: Bildprompt fertig, aber Bildgenerierung (P6) hat nie begonnen.
  if (safeStr(j.visualPromptStage) === 'prompt_ready' &&
      ['', 'not_started'].includes(safeStr(j.imageStage)) &&
      isStale(j.lastAnalysisAt)) {
    findings.push({
      vorgangKey, label,
      check: 'visual_to_image',
      hint: 'visualPromptStage=prompt_ready seit über ' + STALE_HOURS + 'h, aber imageStage=' + (safeStr(j.imageStage) || '(leer)') + ' - Bildgenerierung (P6) hat es nicht abgeholt.'
    });
  }
}

return findings.map(f => ({ json: f }));

// Baut eine Matrix-Sammelmeldung aus allen Dispatcher-Funden. Reine
// Lesestufe - kein DB-Write, kein erneuter Versuch, wenn schon einmal
// gemeldet (bewusst: der Mensch soll das manuell pruefen und die Ursache
// beheben, nicht der Dispatcher automatisch loesen - siehe Notiz im Watchdog-
// Node). Wiederholt sich daher bei jedem Lauf, solange der Zustand anhaelt -
// akzeptabel bei einem 6-Stunden-Intervall.
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

if (!items || items.length === 0) {
  return [];
}

const byCheck = {};
for (const item of items) {
  const j = item.json || {};
  const check = safeStr(j.check) || 'unbekannt';
  if (!byCheck[check]) byCheck[check] = [];
  byCheck[check].push(j);
}

const CHECK_LABELS = {
  ingestion_to_summary: 'Bewertung (P3) nicht abgeholt',
  analysis_to_judgment: 'Agenten-Kette (P3d) nicht abgeholt',
  judgment_to_kernbotschaft: 'Kernbotschaft (P3e) nicht abgeholt',
  visual_to_image: 'Bildgenerierung (P6) nicht abgeholt'
};

let sections = [];
for (const [check, list] of Object.entries(byCheck)) {
  const label = CHECK_LABELS[check] || check;
  const zeilen = list.map(j => `• ${safeStr(j.label) || '?'}\n  ${safeStr(j.hint)}`);
  sections.push(`— ${label} (${list.length}) —\n\n` + zeilen.join('\n\n'));
}

const msg = `🕵️ Dispatcher-Watchdog: ${items.length} liegen gebliebene Vorgänge gefunden\n\n` +
  `Diese Vorgänge haetten laengst von der naechsten Pipeline-Stufe abgeholt ` +
  `werden muessen. Dies ist ein reiner Beobachtungs-Alarm (Paket 7) - es wurde ` +
  `nichts automatisch veraendert:\n\n` +
  sections.join('\n\n');

const txnId = 'dispatch_' + Date.now();

return [{ json: { alertMessage: msg, txnId, findingCount: items.length } }];

const TEST_VORGANG_KEY = '';

if (!TEST_VORGANG_KEY) {
  throw new Error('[Claim-Test] TEST_VORGANG_KEY im Node Konfiguriere Claim-Test setzen. Ohne expliziten Testschluessel erfolgt kein Datenbank-Write.');
}

return [{ json: { vorgangKey: TEST_VORGANG_KEY } }];

if (items.length !== 1) {
  throw new Error(`[Claim-Test] Erwartet genau eine Tabellenzeile, erhalten: ${items.length}.`);
}

const row = items[0].json || {};
const owner = `ALLRIS_Dispatcher_Watchdog:${$execution.id}`;
const acquiredAt = $now.toISO();
const expiresAt = $now.plus({ minutes: 30 }).toISO();

return [{ json: {
  vorgangKey: String(row.vorgangKey || ''),
  expectedClaimOwner: row.claim_owner ?? null,
  expectedClaimExpiresAt: row.claim_expires_at ?? null,
  claimOwner: owner,
  claimStage: 'dispatcher_test',
  claimAcquiredAt: acquiredAt,
  claimExpiresAt: expiresAt
} }];

if (items.length !== 1) {
  throw new Error(`[Claim-Test] Re-Read lieferte ${items.length} Zeilen.`);
}
const row = items[0].json || {};
const expected = $('Bereite Test-Claim vor').item.json;
if (String(row.claim_owner || '') !== String(expected.claimOwner || '')) {
  throw new Error(`[Claim-Test] Claim nicht erworben; Owner ist ${String(row.claim_owner || '(leer)')}.`);
}
return [{ json: { ...expected, claimConfirmed: true } }];

if (items.length !== 1) {
  throw new Error(`[Claim-Test] Abschluss-Read lieferte ${items.length} Zeilen.`);
}
const row = items[0].json || {};
if (row.claim_owner || row.claim_stage || row.claim_acquired_at || row.claim_expires_at) {
  throw new Error('[Claim-Test] Eigener Claim wurde nicht vollständig freigegeben.');
}
return [{ json: { vorgangKey: row.vorgangKey, claimTestPassed: true } }];
